index 000000000..a687c7038
--- /dev/null
+++ b/test/mcp/epics-list.test.ts
@@ -0,0 +1,73 @@
+import { describe, it, expect, vi, beforeEach } from 'vitest';
+import { handle } from '../../server/mcp/tools/epics.js';
+import type { ToolDependencies, ToolResponse } from '../../server/mcp/helpers/types.js';
+import type { IStateManager } from '../../server/state/interface.js';
+
+// ---------------------------------------------------------------------------
+// Mocks
+// ---------------------------------------------------------------------------
+
+vi.mock('../../server/mcp/helpers/session-context.js', () => ({
+  getCurrentUserId: vi.fn(() => 'test-user'),
+  getCurrentOrgId: vi.fn(() => 'test-org'),
+}));
+
+const mockStateManager = {
+  listEpicSummariesPaginated: vi.fn(),
+} as unknown as IStateManager;
+
+function makeDeps(sessionId = ''): ToolDependencies {
+  return {
+    stateManager: mockStateManager,
+    wsHandler: { broadcast: vi.fn() } as unknown as ToolDependencies['wsHandler'],
+    sessionId,
+  };
+}
+
+function parseResponse(response: ToolResponse) {
+  const text = response.content[0].type === 'text' ? (response.content[0] as { text: string }).text : '';
+  return JSON.parse(text);
+}
+
+// ---------------------------------------------------------------------------
+// Tests
+// ---------------------------------------------------------------------------
+
+describe('list_epics MCP tool', () => {
+  beforeEach(() => {
+    vi.clearAllMocks();
+  });
+
+  it('returns total count from pagination metadata if available', async () => {
+    vi.mocked(mockStateManager.listEpicSummariesPaginated).mockResolvedValue({
+      items: [{ id: 'E1', title: 'Epic 1', status: 'active', source: 'mcp', createdAt: '...', tasksTotal: 0, tasksAvailable: 0, tasksInProgress: 0, tasksCompleted: 0 }],
+      pagination: {
+        total: 150,
+        hasMore: true,
+        nextCursor: 'cursor-123'
+      }
+    });
+
+    const result = await handle('list_epics', {}, makeDeps());
+
+    expect(result.isError).toBeUndefined();
+    const payload = parseResponse(result);
+    expect(payload.total).toBe(150);
+    expect(payload.epics).toHaveLength(1);
+  });
+
+  it('falls back to items.length if total is missing from pagination', async () => {
+    vi.mocked(mockStateManager.listEpicSummariesPaginated).mockResolvedValue({
+      items: [{ id: 'E1', title: 'Epic 1', status: 'active', source: 'mcp', createdAt: '...', tasksTotal: 0, tasksAvailable: 0, tasksInProgress: 0, tasksCompleted: 0 }],
+      pagination: {
+        hasMore: false
+      }
+    });
+
+    const result = await handle('list_epics', {}, makeDeps());
+
+    expect(result.isError).toBeUndefined();
+    const payload = parseResponse(result);
+    expect(payload.total).toBe(1);
+  });
+});
diff --git a/test/mcp/epics-tool.test.ts b/test/mcp/epics-tool.test.ts
