@@ -145,3 +145,29 @@ describe('get_epic MCP tool — externalRef fields', () => {
     expect(payload.error).toBe('not_found');
   });
 });
+
+describe('get_epic MCP tool — validation', () => {
+  it('returns an error when epic_id is missing', async () => {
+    const result = await handle('get_epic', {}, makeDeps());
+    expect(result.isError).toBe(true);
+    const payload = JSON.parse(result.content[0].text);
+    expect(payload.error).toBe('missing_epic_id');
+    expect(payload.message).toContain('epic_id is required');
+  });
+
+  it('returns an error when epic_id is whitespace-only', async () => {
+    const result = await handle('get_epic', { epic_id: '   ' }, makeDeps());
+    expect(result.isError).toBe(true);
+    const payload = JSON.parse(result.content[0].text);
+    expect(payload.error).toBe('missing_epic_id');
+    expect(payload.message).toContain('epic_id is required');
+  });
+
+  it('trims surrounding whitespace from epic_id before lookup', async () => {
+    vi.mocked(mockStateManager.getEpic).mockResolvedValue(null);
+    vi.mocked(mockStateManager.listTasks).mockResolvedValue([]);
+    vi.mocked(mockStateManager.listFeaturesForTasks).mockResolvedValue(new Map());
+    await handle('get_epic', { epic_id: '  AUTH-1  ' }, makeDeps());
+    expect(mockStateManager.getEpic).toHaveBeenCalledWith('AUTH-1');
+  });
+});
